{
  "executive_summary": "Architecture for a real-time courier bidding system handling 500 concurrent bid windows with atomic first-to-accept semantics. The design centers on Redis for atomic bid resolution (compare-and-swap), WebSockets for sub-second courier notifications, and a delayed-queue mechanism for the 15-second timeout fallback. Peak concurrent connections: ~15,000 couriers across all active windows. The critical invariant — exactly one courier wins each job — is enforced at the data layer via Redis atomic operations, not application logic.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingestion Service",
        "responsibility": "Receives new orders from the marketplace API, validates them, determines the delivery zone, and emits a JobCreated domain event. Stateless HTTP service.",
        "boundaries": "Owns order validation and zone resolution. Does NOT decide courier eligibility — that belongs to the Matching Engine."
      },
      {
        "name": "Matching Engine",
        "responsibility": "Subscribes to JobCreated events. Queries the Courier Availability Index to determine eligible couriers for the zone. Creates a BidWindow aggregate in Redis and fans out job offers to all eligible couriers via the Notification Gateway. Schedules a 15-second timeout callback.",
        "boundaries": "Owns eligibility logic (zone, active status, current load). Does NOT own courier profiles or ratings — reads them from Courier Context."
      },
      {
        "name": "Bid Window (Redis Aggregate)",
        "responsibility": "The core consistency boundary. A Redis hash per job storing: job_id, status (open|claimed|expired), winner_courier_id, created_at, eligible_courier_ids. All state transitions are performed via Lua scripts for atomicity.",
        "boundaries": "Single source of truth for bid resolution. All accept/expire operations go through this aggregate. No other component may mutate bid state."
      },
      {
        "name": "Bid Acceptance Service",
        "responsibility": "Receives courier accept requests via WebSocket or HTTP. Executes an atomic Redis Lua script: IF status == 'open' THEN set status='claimed', winner=courier_id, RETURN 'won' ELSE RETURN 'lost'. Emits JobClaimed or BidRejected event based on result.",
        "boundaries": "Stateless. All atomicity is delegated to Redis Lua. This service is the only writer to the Bid Window aggregate (besides the Timeout Worker)."
      },
      {
        "name": "Timeout Worker",
        "responsibility": "Processes expired bid windows. Uses a Redis sorted set (ZRANGEBYSCORE) keyed by expiry timestamp. Every 500ms, polls for expired windows. For each expired window still in 'open' status, executes a Lua script to atomically transition to 'expired' and selects the highest-rated available courier as fallback assignee. Emits JobAutoAssigned event.",
        "boundaries": "Only activates for windows that reach the 15-second deadline without acceptance. Competes atomically with Bid Acceptance Service — the Lua script ensures exactly one wins."
      },
      {
        "name": "Notification Gateway (WebSocket Layer)",
        "responsibility": "Maintains persistent WebSocket connections with courier mobile apps. Fans out job offers to eligible couriers when a bid window opens. Pushes 'job taken' notifications to losing couriers when a window closes. Handles presence tracking (courier online/offline).",
        "boundaries": "Transport only — no business logic. Does not decide eligibility or resolve bids. Horizontally scaled with sticky sessions via consistent hashing on courier_id."
      },
      {
        "name": "Courier Availability Index",
        "responsibility": "Maintains a real-time view of courier availability per zone. Updated by courier location pings, job assignments, and shift start/end events. Stored as Redis sets keyed by zone_id. Includes courier rating for fallback ranking.",
        "boundaries": "Read-heavy, eventually consistent. A courier appearing in the index does not guarantee they will accept — it is a best-effort eligibility filter."
      },
      {
        "name": "Event Bus (Message Broker)",
        "responsibility": "Carries domain events (JobCreated, JobClaimed, JobAutoAssigned, BidWindowExpired, CourierLocationUpdated) between services. Kafka or Redis Streams depending on durability requirements.",
        "boundaries": "At-least-once delivery. Consumers must be idempotent."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingestion Service",
        "to": "Event Bus",
        "contract": "Publishes JobCreated { job_id, pickup, dropoff, zone_id, order_details, created_at }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Matching Engine",
        "to": "Courier Availability Index",
        "contract": "SMEMBERS zone:{zone_id}:available → Set<{ courier_id, rating, location }> — read-only query",
        "coupling_type": "data (sync read, loose)"
      },
      {
        "from": "Matching Engine",
        "to": "Bid Window (Redis)",
        "contract": "HSET + SADD to create bid window: bidwindow:{job_id} = { status: 'open', eligible: [...], created_at, expires_at }",
        "coupling_type": "data (sync write, tight — intentional)"
      },
      {
        "from": "Matching Engine",
        "to": "Notification Gateway",
        "contract": "POST /internal/fanout { job_id, courier_ids[], job_summary, expires_at } — triggers WebSocket push to each courier",
        "coupling_type": "request-response (sync, moderate)"
      },
      {
        "from": "Courier Mobile App",
        "to": "Bid Acceptance Service",
        "contract": "WS message or POST /bids/accept { job_id, courier_id, timestamp } → { result: 'won' | 'lost', job_id }",
        "coupling_type": "request-response (sync, tight — latency-critical)"
      },
      {
        "from": "Bid Acceptance Service",
        "to": "Bid Window (Redis)",
        "contract": "EVALSHA claim_bid.lua { job_id, courier_id } → atomically: if open → claimed+winner, return 'won'; else return 'lost'",
        "coupling_type": "data (sync, tight — the core invariant boundary)"
      },
      {
        "from": "Timeout Worker",
        "to": "Bid Window (Redis)",
        "contract": "EVALSHA expire_bid.lua { job_id, fallback_courier_id } → atomically: if still open → expired+assignee, return 'assigned'; else return 'already_claimed'",
        "coupling_type": "data (sync, tight)"
      },
      {
        "from": "Bid Acceptance Service",
        "to": "Notification Gateway",
        "contract": "POST /internal/notify-resolution { job_id, winner_courier_id, losing_courier_ids[] } — pushes 'job taken' to losers, confirmation to winner",
        "coupling_type": "event (async fire-and-forget, loose)"
      }
    ],
    "data_flow": "1) Order placed → Order Ingestion validates → publishes JobCreated to Event Bus. 2) Matching Engine consumes JobCreated → queries Courier Availability Index for zone → creates Bid Window in Redis with 15s TTL → fans out job offer to eligible couriers via Notification Gateway WebSocket push → inserts expiry timestamp into Redis sorted set for Timeout Worker. 3) Couriers see job on mobile → tap Accept → Bid Acceptance Service receives request → executes atomic Lua script against Redis Bid Window → first courier gets 'won', all others get 'lost' → publishes JobClaimed event → Notification Gateway pushes resolution to all couriers in window. 4) If no courier accepts within 15s → Timeout Worker picks up expired entry → executes atomic Lua fallback assignment to highest-rated courier → publishes JobAutoAssigned event → Notification Gateway notifies assigned courier.",
    "patterns_used": [
      {
        "pattern": "Atomic Compare-and-Swap via Redis Lua Scripts",
        "rationale": "The critical invariant (exactly one winner per job) cannot be enforced at the application layer due to race conditions. Redis Lua scripts execute atomically — the EVAL command blocks all other commands until the script completes. This gives us serializable isolation for the bid resolution without distributed locks or database transactions. At 500 concurrent windows with 30 couriers each, worst-case 15,000 near-simultaneous accept attempts, Redis single-threaded execution handles this trivially (sub-millisecond per Lua eval)."
      },
      {
        "pattern": "Delayed Queue / Sorted Set Timer",
        "rationale": "The 15-second timeout must be reliable even if services restart. A Redis sorted set keyed by expiry epoch (ZADD timeouts <expiry_ts> <job_id>) allows the Timeout Worker to poll with ZRANGEBYSCORE -inf <now> efficiently. This avoids in-process timers (which die with the process) and is simpler than a full scheduling system."
      },
      {
        "pattern": "Fan-out via WebSocket with Presence Tracking",
        "rationale": "Push-based notification is essential for the 15-second real-time window. Polling would consume the window budget. WebSocket connections give sub-200ms delivery to couriers. Presence tracking (heartbeat-based) lets the Matching Engine exclude offline couriers from eligibility, reducing wasted fan-out."
      },
      {
        "pattern": "Event-Driven Architecture for Cross-Boundary Communication",
        "rationale": "Services outside the hot path (order history, analytics, courier performance tracking) subscribe to domain events asynchronously. This keeps the critical bid resolution path fast and decoupled from downstream concerns."
      },
      {
        "pattern": "CQRS-lite on Courier Availability",
        "rationale": "The Courier Availability Index is a read-optimized projection maintained by consuming location and status events. It is eventually consistent (acceptable: a courier going offline mid-bid window is handled gracefully by the 'lost' response if they never accept). This avoids querying a normalized database on every job match."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Bidding Context",
        "classification": "core",
        "aggregates": [
          "BidWindow — aggregate root. Fields: job_id (identity), status (open|claimed|expired), winner_courier_id, eligible_courier_ids, created_at, expires_at. Invariant: status transitions are one-way (open→claimed OR open→expired, never back). Only one winner can be set. Implemented as a Redis hash + Lua scripts for atomicity."
        ]
      },
      {
        "name": "Order Context",
        "classification": "supporting",
        "aggregates": [
          "Order — aggregate root. Fields: order_id, pickup, dropoff, zone_id, status (placed|bidding|assigned|in_transit|delivered), customer_id. Transitions to 'bidding' when JobCreated is emitted, to 'assigned' when JobClaimed/JobAutoAssigned is received."
        ]
      },
      {
        "name": "Courier Context",
        "classification": "supporting",
        "aggregates": [
          "CourierProfile — aggregate root. Fields: courier_id, rating, zones[], vehicle_type, max_concurrent_jobs, current_job_count. Owns the courier's identity, rating, and capacity.",
          "CourierAvailability — value object projected into the Availability Index. Fields: courier_id, zone_id, is_online, last_location, rating. Rebuilt from events."
        ]
      },
      {
        "name": "Notification Context",
        "classification": "generic",
        "aggregates": [
          "ConnectionRegistry — tracks active WebSocket connections per courier. No domain logic — pure infrastructure."
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Context",
        "downstream": "Bidding Context",
        "relationship": "Customer-Supplier. Order Context publishes JobCreated; Bidding Context consumes it to open a bid window. Bidding Context does not modify orders — it publishes resolution events that Order Context consumes to update order status."
      },
      {
        "upstream": "Courier Context",
        "downstream": "Bidding Context",
        "relationship": "Conformist. Bidding Context reads courier availability and ratings as-is. It conforms to the Courier Context's model for eligibility and fallback ranking. No translation layer needed — the data is simple (id, rating, zone)."
      },
      {
        "upstream": "Bidding Context",
        "downstream": "Notification Context",
        "relationship": "Open Host Service. Bidding Context exposes fan-out and resolution commands via an internal API. Notification Context is a generic transport layer that conforms to whatever the Bidding Context tells it to send."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Redis as the single source of truth for bid resolution (not PostgreSQL)",
      "gains": "Sub-millisecond atomic operations. Lua scripts provide serializable isolation without locks. Handles 500 concurrent windows trivially. No connection pool pressure.",
      "sacrifices": "Redis is an in-memory store — data loss on crash unless persistence is configured. Less queryable than SQL for analytics. Requires Redis Cluster for HA.",
      "alternatives_considered": [
        "PostgreSQL with SELECT FOR UPDATE — adds 2-5ms per bid resolution, creates lock contention at 500 concurrent windows, connection pool exhaustion risk",
        "DynamoDB conditional writes — viable but adds network latency (~5-15ms) and costs more at this write volume",
        "Application-level distributed lock (Redlock) — more complex, higher failure modes than single-instance Lua"
      ]
    },
    {
      "decision": "Polling-based Timeout Worker (sorted set scan every 500ms) instead of per-job scheduled timers",
      "gains": "Survives process restarts — expiry state lives in Redis, not in-process memory. Simple to implement. No timer wheel complexity. 500ms polling adds at most 500ms to a 15-second window — acceptable.",
      "sacrifices": "Slight delay (up to 500ms) before expired windows are processed. Not perfectly precise at the 15-second mark.",
      "alternatives_considered": [
        "Redis keyspace notifications on TTL expiry — unreliable (at-most-once, can be missed under load)",
        "In-process timer per bid window — dies if process restarts, requires careful cleanup",
        "Kafka delayed messages — overkill for this use case, adds operational complexity"
      ]
    },
    {
      "decision": "WebSocket for courier communication instead of push notifications (FCM/APNs)",
      "gains": "Sub-200ms latency for job offers and resolution. Bidirectional — courier can send accept over the same connection. Real-time presence detection via heartbeat.",
      "sacrifices": "Requires maintaining ~15,000 persistent connections (500 windows × 30 couriers, though many overlap). More infrastructure than fire-and-forget push. Mobile apps must handle reconnection gracefully.",
      "alternatives_considered": [
        "FCM/APNs push notifications — 1-3 second latency is too high for a 15-second window; unreliable delivery timing",
        "Server-Sent Events — one-directional, courier still needs HTTP POST for accept; two protocols instead of one",
        "Long polling — higher latency, more server load, less efficient than WebSocket"
      ]
    },
    {
      "decision": "Single Redis instance (not cluster) for the bid resolution hot path",
      "gains": "Lua scripts work without cross-slot concerns. Simpler operations. Single-threaded guarantees are straightforward. At 500 concurrent windows, a single Redis instance handles the load easily (100K+ ops/sec capacity vs ~15K peak ops/sec needed).",
      "sacrifices": "Single point of failure without replication. Vertical scaling limit (though we are far from it).",
      "alternatives_considered": [
        "Redis Cluster — needed if we exceed single-instance capacity, but adds complexity with hash slots and Lua script restrictions (all keys in same slot)",
        "Redis Sentinel for HA — recommended as the first step toward resilience without cluster complexity"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Matching/Eligibility Logic",
      "evolution_path": "Currently zone-based. Can evolve to radius-based, weighted scoring (distance + rating + acceptance rate), or ML-based matching. The Matching Engine is a standalone service consuming from the Availability Index — swap the algorithm without touching bid resolution."
    },
    {
      "area": "Bid Window Duration",
      "evolution_path": "The 15-second window is a configuration parameter on the BidWindow aggregate. Can be made dynamic per zone (shorter in high-density areas), per time-of-day, or per job urgency. No architectural change needed."
    },
    {
      "area": "Fallback Assignment Strategy",
      "evolution_path": "Currently highest-rated courier. The Timeout Worker's fallback logic can evolve to consider distance, current load, historical acceptance rate, or even trigger a second-round bid window. The fallback is isolated in the expire Lua script and the Timeout Worker."
    },
    {
      "area": "Notification Transport",
      "evolution_path": "The Notification Gateway is a generic transport layer. Can add FCM/APNs as a fallback for couriers whose WebSocket dropped. Can add SMS for critical assignments. The Bidding Context doesn't know or care about transport."
    },
    {
      "area": "Bid Model (First-Accept → Auction)",
      "evolution_path": "If the business evolves to price-based bidding (couriers bid a price, lowest wins after timeout), the BidWindow aggregate gains a bids[] array and the Lua script changes from compare-and-swap to insert-and-rank. The architecture accommodates this — the timeout already exists, and the resolution logic is centralized in Lua scripts."
    }
  ],

  "rigidity_points": [
    {
      "area": "Redis as the bid resolution engine",
      "reason": "The entire atomicity guarantee depends on Redis Lua script execution semantics. Migrating to a different store requires re-implementing the atomic bid resolution — this is intentional rigidity protecting the core invariant."
    },
    {
      "area": "Exactly-one-winner invariant",
      "reason": "This is a business-critical invariant that must never be relaxed. The Lua script, the BidWindow state machine (open→claimed|expired), and the single-writer pattern all exist to enforce it. Any architectural change must preserve this guarantee."
    },
    {
      "area": "WebSocket as the primary real-time channel",
      "reason": "The 15-second window makes sub-second delivery non-negotiable. While the transport layer is abstracted, the system requires a push-based, low-latency channel. You cannot replace this with polling or batch processing."
    }
  ],

  "risks": [
    {
      "risk": "Redis single-instance failure causes all active bid windows to be lost",
      "severity": "critical",
      "mitigation": "Deploy Redis with Sentinel for automatic failover. Enable AOF persistence with fsync every second (1s max data loss). For zero-loss, use Redis with synchronous replication to a replica (WAIT command) — adds ~1ms latency per write, acceptable for this use case. Additionally, the Matching Engine should be able to re-create bid windows from the Event Bus replay if Redis recovers empty."
    },
    {
      "risk": "Courier accepts job but WebSocket notification of 'won' is lost — courier doesn't know they won",
      "severity": "high",
      "mitigation": "The accept response is returned synchronously to the courier's accept request (HTTP response or WebSocket reply frame), not via a separate push. The courier knows immediately. Additionally, the mobile app should poll GET /bids/{job_id}/status as a fallback if no response within 2 seconds."
    },
    {
      "risk": "Clock skew between Timeout Worker and Redis causes premature or late expiry",
      "severity": "medium",
      "mitigation": "Use Redis server time (TIME command) for all timestamp comparisons, not local system time. The Timeout Worker passes Redis-derived timestamps to ZRANGEBYSCORE. NTP sync on all hosts as defense-in-depth."
    },
    {
      "risk": "Thundering herd: 500 jobs × 30 couriers = 15,000 WebSocket pushes in a burst when many orders arrive simultaneously",
      "severity": "medium",
      "mitigation": "The Notification Gateway should use a bounded outbound queue with backpressure. Stagger fan-out across 100-200ms if needed (still well within the 15s window). Horizontal scaling of WebSocket servers with load balancing on courier_id hash."
    },
    {
      "risk": "Courier appears eligible but has gone offline between availability check and bid window open",
      "severity": "low",
      "mitigation": "Not a real problem. Offline couriers simply never accept. The 15-second timeout with fallback assignment handles this gracefully. The Availability Index heartbeat (every 10s) keeps staleness bounded."
    },
    {
      "risk": "Timeout Worker process crash leaves expired windows unprocessed",
      "severity": "high",
      "mitigation": "Run 2+ Timeout Worker instances. The Lua expire script is idempotent — multiple workers can safely attempt to expire the same window. Only the first succeeds (atomic CAS). Use a leader election or simply let all workers poll — the Lua script prevents double-assignment."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1: Implement the BidWindow Redis aggregate with Lua scripts (claim + expire). Write exhaustive concurrency tests — spin up 30 goroutines/threads hitting accept simultaneously, verify exactly 1 wins. Phase 2: Build the Matching Engine and Timeout Worker. Phase 3: Add WebSocket Notification Gateway. Phase 4: Integrate with Order Context via events. Start with a single Redis instance + Sentinel. The Lua scripts are the highest-risk, highest-value component — get them right first.",
    "files_to_create_or_modify": [
      "src/bidding/lua/claim_bid.lua — Atomic claim script: HGET status, if 'open' then HSET status='claimed' winner=courier_id, SREM from timeout sorted set, return 'won'; else return 'lost'",
      "src/bidding/lua/expire_bid.lua — Atomic expire script: HGET status, if 'open' then HSET status='expired' assignee=fallback_courier_id, return 'assigned'; else return 'already_claimed'",
      "src/bidding/bid_window_repository.ts — TypeScript wrapper around Redis Lua scripts. Methods: create(jobId, eligibleCouriers, expiresAt), claim(jobId, courierId), getStatus(jobId)",
      "src/bidding/matching_engine.ts — Consumes JobCreated events, queries availability index, creates bid window, triggers fan-out",
      "src/bidding/timeout_worker.ts — Polls Redis sorted set every 500ms, processes expired windows with fallback logic",
      "src/bidding/bid_acceptance_handler.ts — WebSocket/HTTP handler for courier accept requests, calls bid_window_repository.claim()",
      "src/notification/websocket_gateway.ts — WebSocket server with connection registry, fan-out, and presence heartbeat",
      "src/courier/availability_index.ts — Redis set-based availability per zone, updated by location/status events",
      "tests/bidding/concurrent_claim_test.ts — Concurrency tests: N simultaneous claims, verify exactly 1 winner",
      "tests/bidding/timeout_race_test.ts — Race between claim and expire, verify no double-assignment"
    ],
    "patterns_to_follow": "Repository pattern for Redis aggregate access. Event-driven for cross-context communication. Idempotent consumers on all event handlers. Structured logging with correlation IDs (job_id) on every log line for traceability. Circuit breaker on the Notification Gateway fan-out. Health checks on Redis connectivity.",
    "pitfalls_to_avoid": [
      "DO NOT implement bid resolution in application code with read-then-write — this has a race condition window. ALL state transitions MUST happen inside Redis Lua scripts.",
      "DO NOT use Redis WATCH/MULTI transactions as an alternative to Lua — they use optimistic locking and will fail under high contention (30 couriers hitting accept simultaneously), causing retry storms.",
      "DO NOT use in-process timers (setTimeout, ScheduledExecutor) for the 15-second window — they are lost on process restart and don't scale across instances.",
      "DO NOT send the 'job taken' notification to losing couriers before confirming the winner's accept response was delivered — this prevents confusion if the winner's connection dropped.",
      "DO NOT make the WebSocket Gateway call the Bid Acceptance Service — keep the accept path direct (courier → Bid Acceptance Service → Redis). The WebSocket layer is for push notifications only, not for proxying business operations.",
      "DO NOT store bid windows in PostgreSQL for the hot path — it will become a bottleneck under concurrent writes. Use PostgreSQL only for post-resolution persistence (event sourcing or CDC from Redis)."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Redis Lua for atomic bid resolution — this is a well-proven pattern for exactly-once semantics in high-concurrency scenarios",
      "WebSocket for real-time courier notification — the 15-second window makes this the only viable choice",
      "Sorted set timer for timeout processing — simple, reliable, battle-tested",
      "500 concurrent windows is well within single Redis instance capacity",
      "Domain model boundaries — Bidding, Order, Courier, Notification contexts are natural seams"
    ],
    "low_confidence_areas": [
      "Optimal Timeout Worker polling interval (500ms is a starting point — may need tuning based on observed expiry precision requirements)",
      "Whether Redis Sentinel is sufficient or Redis Cluster will be needed as the system scales beyond 500 concurrent windows",
      "Mobile app reconnection behavior and its impact on notification delivery reliability — depends heavily on mobile platform constraints"
    ],
    "assumptions": [
      "The 500 concurrent bid windows figure represents peak load, not sustained baseline",
      "Couriers have reasonably stable mobile connectivity (urban delivery, not rural)",
      "The 'first to accept wins' model is final — not evolving to price-based auction in the near term",
      "Courier ratings are pre-computed and available in the Availability Index — not calculated on-the-fly",
      "A single geographic region / data center is sufficient — no multi-region requirement yet"
    ]
  }
}

